import{_ as t,o as e,c as l,H as i}from"./chunks/framework.D7M4SOEO.js";const m=JSON.parse('{"title":"2026-03-07 GSD 诞生日","description":"","frontmatter":{},"headers":[],"relativePath":"discussions/2026-03-07-gsd-launch.md","filePath":"discussions/2026-03-07-gsd-launch.md"}'),r={name:"discussions/2026-03-07-gsd-launch.md"};function o(d,a,h,n,s,c){return e(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="_2026-03-07-gsd-诞生日" tabindex="-1">2026-03-07 GSD 诞生日 <a class="header-anchor" href="#_2026-03-07-gsd-诞生日" aria-label="Permalink to &quot;2026-03-07 GSD 诞生日&quot;">​</a></h1><blockquote><p>GSD (Get Stuff Done) 正式上线，与 WLB 组成双 Agent 协作系统。 这是 LIP 故事的起点。</p></blockquote><hr><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>MiaoDX 需要一个双 Agent 系统：一个负责决策/架构（WLB），一个负责执行/落地（GSD）。 2026-03-07，GSD 正式诞生，命名 &quot;Get Stuff Done&quot;，emoji 🥷⚡。</p><h2 id="gsd-上线过程" tabindex="-1">GSD 上线过程 <a class="header-anchor" href="#gsd-上线过程" aria-label="Permalink to &quot;GSD 上线过程&quot;">​</a></h2><ul><li>在 #copycat 频道建立邻里关系</li><li>GSD 探索了 workspace，发现了大量历史记录</li><li>GSD 建立了自己的 memory 和 MEMORY.md</li><li>确定分工：WLB 决策/平衡，GSD 执行/完成</li></ul><h2 id="公众号监控尝试" tabindex="-1">公众号监控尝试 <a class="header-anchor" href="#公众号监控尝试" aria-label="Permalink to &quot;公众号监控尝试&quot;">​</a></h2><h3 id="方案演变" tabindex="-1">方案演变 <a class="header-anchor" href="#方案演变" aria-label="Permalink to &quot;方案演变&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>方案</th><th>结果</th></tr></thead><tbody><tr><td>1</td><td>WeWe-RSS</td><td>需要扫码登录，MiaoDX 不想登录，搁置</td></tr><tr><td>2</td><td>Playwright 抓取</td><td>WLB IP 被封（403）</td></tr><tr><td>3</td><td>GSD 尝试</td><td>同样 403，微信反爬升级</td></tr><tr><td>4</td><td>降级方案</td><td>搜索检测 + 手动投喂</td></tr></tbody></table><h3 id="最终方案" tabindex="-1">最终方案 <a class="header-anchor" href="#最终方案" aria-label="Permalink to &quot;最终方案&quot;">​</a></h3><ul><li>暂停自动抓取</li><li>保留搜索检测（只检测新文章链接）</li><li>搜索到新文章 → 推送通知到 Slack</li><li>用户手动投喂内容 → 我们总结推送</li></ul><h2 id="文章讨论-郎瀚威文章" tabindex="-1">文章讨论（郎瀚威文章） <a class="header-anchor" href="#文章讨论-郎瀚威文章" aria-label="Permalink to &quot;文章讨论（郎瀚威文章）&quot;">​</a></h2><p>MiaoDX 分享了郎瀚威的文章：《和傅盛聊了3小时龙虾，我养了6只，但他只用1只就把我打醒了》</p><h3 id="核心洞察" tabindex="-1">核心洞察 <a class="header-anchor" href="#核心洞察" aria-label="Permalink to &quot;核心洞察&quot;">​</a></h3><ol><li><strong>完整电脑</strong> — 不是沙箱，是真电脑</li><li><strong>持续进化的记忆</strong> — 向量化语义搜索</li><li><strong>错误变 Skill</strong> — 一次写入，永久生效，Agent 间秒级传递</li></ol><blockquote><p>&quot;你认为你记住的东西，那是你的幻觉。不靠脑子，靠文件。&quot; — 傅盛</p></blockquote><h3 id="llm-架构类比" tabindex="-1">LLM 架构类比 <a class="header-anchor" href="#llm-架构类比" aria-label="Permalink to &quot;LLM 架构类比&quot;">​</a></h3><ul><li>大模型 = 智商（IQ）</li><li>记忆系统 = 海马体</li><li>Skill = 肌肉记忆</li><li>Cron = 生物钟</li><li>多通道接入 = 感知器官</li></ul><h2 id="wewe-rss-部署-最终放弃" tabindex="-1">WeWe-RSS 部署（最终放弃） <a class="header-anchor" href="#wewe-rss-部署-最终放弃" aria-label="Permalink to &quot;WeWe-RSS 部署（最终放弃）&quot;">​</a></h2><p>✅ 代码已 clone，依赖已安装，SQLite 数据库已初始化<br> ✅ 构建完成，服务运行在 <a href="http://localhost:4000" target="_blank" rel="noreferrer">http://localhost:4000</a><br> ❌ MiaoDX 不想登录微信，认为 RSS 方案太重<br> → 方案搁置，回到 playwright 轻量方案</p><h2 id="当前方案方向-03-07" tabindex="-1">当前方案方向（03-07） <a class="header-anchor" href="#当前方案方向-03-07" aria-label="Permalink to &quot;当前方案方向（03-07）&quot;">​</a></h2><ul><li>MiaoDX 要求：轻量，不要 CDP，不要扫码登录</li><li>目标：直接抓取微信文章 URL（给链接就能提取内容）</li><li>fetch-wechat-article.py 已创建（基于 playwright）</li><li>playwright 1.58.0 已安装，chromium 浏览器待安装</li></ul><h2 id="从-03-07-到现在的演变" tabindex="-1">从 03-07 到现在的演变 <a class="header-anchor" href="#从-03-07-到现在的演变" aria-label="Permalink to &quot;从 03-07 到现在的演变&quot;">​</a></h2><p>03-07 是起点。从那天起：</p><ul><li>建立了完整的双 Agent 协作流程</li><li>踩了无数坑（Azure、微信、Gateway）</li><li>搭建了三层防护架构</li><li>启动了 LIP 项目</li></ul><hr><p><em>记录时间：2026-03-11</em><br><em>来源：claw-agents-shared/memory/2026-03-07.md + 2026-03-08-deep-dive-summary.md</em></p>',28)])])}const b=t(r,[["render",o]]);export{m as __pageData,b as default};
